+    #[test]
+    fn validation_error_display_all_variants() {
+        let errors = vec![
+            E2eArtifactValidationError::UnsupportedSchemaVersion {
+                expected: 1,
+                found: 2,
+            },
+            E2eArtifactValidationError::SchemaTagMismatch {
+                expected: "e2e-manifest-v1",
