+            E2eArtifactValidationError::DuplicateArtifactEntry {
+                file: "dup.json".into(),
+            },
+            E2eArtifactValidationError::MissingLineCountForJsonl {
+                file: "test.jsonl".into(),
+            },
+            E2eArtifactValidationError::UnexpectedLineCountForNonJsonl {
